CREATE TABLE IF NOT EXISTS ORDER_RESULT (
    `PATIENTID` VARCHAR(13),
    `ORDER_ID` VARCHAR(15),
    `ENCOUNTER_ID` VARCHAR(15),
    `RESULT_TIME` DATETIME,
    `EXTERNAL_NAME` VARCHAR(30),
    `ORD_NUM_VALUE` INT
);

    
CREATE TABLE IF NOT EXISTS BIOMARKER (
    `SOURCE_ACCESSION_ID` INT,
    `DATA_SOURCE_ID` INT,
    `SOURCE_LAB_NM` VARCHAR(11),
    `SPECIMEN_COLLECTED_DT` DATETIME,
    `REPORT_DT` DATETIME,
    `TEST_ORDERED_DT` DATETIME,
    `TEST_PERFORMED` VARCHAR(73),
    `TISSUE_TYPE_DSC` VARCHAR(50),
    `INSERT_DTS` VARCHAR(31)
);

    
    
    
